B3_quality_gate_d1.SQLScript:
-- DQ checks: duplicates + nulls + zero-sum
DECLARE @dups INT, @nulls INT, @zeros INT;
SELECT @dups = COUNT(*) - COUNT(DISTINCT trade_id)
  FROM dbo.ADWPM_MOVIMENTO_NEGOCIO_DERIVATIVO
  WHERE business_date = ?;
SELECT @nulls = COUNT(*)
  FROM dbo.ADWPM_POSICAO_DERIVATIVO_NAO_FUNGIVEL
  WHERE business_date = ? AND settlement_price IS NULL;
SELECT @zeros = COUNT(*)
  FROM dbo.ADWPM_POSICAO_MERCADO_A_VISTA
  WHERE business_date = ? AND (long_value + short_value) = 0;
IF (@dups > 0 OR @nulls > 0 OR @zeros > 0)
  RAISERROR('DQ FAIL: dups=%d nulls=%d zeros=%d', 16, 1, @dups, @nulls, @zeros);
